import{_ as a,o as s,c as r,ai as i,tQ as n,tR as o,tS as t,tT as l,tU as d}from"./chunks/framework.DIUhWiTt.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notas/PortSwigger/5.Authentication vulnerabilities/10.Password reset broken logic/10.Password reset broken logic.md","filePath":"notas/PortSwigger/5.Authentication vulnerabilities/10.Password reset broken logic/10.Password reset broken logic.md"}'),u={name:"notas/PortSwigger/5.Authentication vulnerabilities/10.Password reset broken logic/10.Password reset broken logic.md"};function c(p,e,m,b,g,h){return s(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="resetting-user-passwords" tabindex="-1">Resetting user passwords <a class="header-anchor" href="#resetting-user-passwords" aria-label="Permalink to “Resetting user passwords”">​</a></h2><p>En la práctica, algunos usuarios olvidan su contraseña, por lo que es habitual que dispongan de un método para restablecerla. Como la autenticación habitual basada en contraseña es obviamente imposible en este escenario, los sitios web tienen que confiar en métodos alternativos para asegurarse de que el usuario real está restableciendo su propia contraseña. Por esta razón, la funcionalidad de restablecimiento de contraseña es intrínsecamente peligrosa y debe implementarse de forma segura.</p><p>Existen varias formas de implementar esta función, con distintos grados de vulnerabilidad.</p><h2 id="sending-passwords-by-email" tabindex="-1">Sending passwords by email <a class="header-anchor" href="#sending-passwords-by-email" aria-label="Permalink to “Sending passwords by email”">​</a></h2><p>Ni que decir tiene que no debería ser posible enviar a los usuarios su contraseña actual si un sitio web gestiona las contraseñas de forma segura en primer lugar. En su lugar, algunos sitios web generan una nueva contraseña y la envían al usuario por correo electrónico.</p><p>En general, debe evitarse el envío de contraseñas persistentes a través de canales inseguros. En este caso, la seguridad depende de que la contraseña generada caduque al cabo de muy poco tiempo o de que el usuario vuelva a cambiarla inmediatamente. De lo contrario, este enfoque es muy susceptible a los ataques de intermediario.</p><p>Por lo general, el correo electrónico tampoco se considera seguro, ya que las bandejas de entrada son persistentes y no están diseñadas para almacenar información confidencial de forma segura. Muchos usuarios también sincronizan automáticamente su bandeja de entrada entre varios dispositivos a través de canales inseguros.</p><h2 id="resetting-passwords-using-a-url" tabindex="-1">Resetting passwords using a URL <a class="header-anchor" href="#resetting-passwords-using-a-url" aria-label="Permalink to “Resetting passwords using a URL”">​</a></h2><p>Un método más robusto para restablecer contraseñas es enviar una URL única a los usuarios que les lleve a una página de restablecimiento de contraseñas. Las implementaciones menos seguras de este método utilizan una URL con un parámetro fácil de adivinar para identificar qué cuenta se está restableciendo, por ejemplo:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//vulnerable-website.com/reset-password?user=victim-user</span></span></code></pre></div><p>En este ejemplo, un atacante podría cambiar el parámetro de usuario para referirse a cualquier nombre de usuario que haya identificado. A continuación, se les llevaría directamente a una página en la que podrían establecer una nueva contraseña para este usuario arbitrario.</p><p>Una mejor implementación de este proceso es generar un token de alta entropía y difícil de adivinar y crear la URL de restablecimiento basada en él. En el mejor de los casos, esta URL no debería proporcionar ninguna pista sobre qué contraseña de usuario se está restableciendo.</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//vulnerable-website.com/reset-password?token=a0ba0d1cb3b63d13822572fcff1a241895d893f659164d4cc550b421ebdd48a8</span></span></code></pre></div><p>Cuando el usuario visita esta URL, el sistema debe comprobar si este token existe en el back-end y, en caso afirmativo, qué contraseña de usuario se supone que debe restablecer. Este token debería caducar tras un breve periodo de tiempo y destruirse inmediatamente después de restablecer la contraseña.</p><p>Sin embargo, algunos sitios web no vuelven a validar el token cuando se envía el formulario de restablecimiento. En este caso, un atacante podría simplemente visitar el formulario de restablecimiento desde su propia cuenta, eliminar el token y aprovechar esta página para restablecer la contraseña de un usuario arbitrario.</p><h2 id="lab" tabindex="-1">LAB <a class="header-anchor" href="#lab" aria-label="Permalink to “LAB”">​</a></h2><p><img src="'+n+'" alt="20250805020854.png"></p><p>El sitio web permite al usuario hacer el reset de la contraseña a través de la funcionalidad de <code>forgot password</code></p><p><img src="'+o+'" alt="20250806005535.png"></p><p>Luego de ingresar nuestro correo este nos da un mensaje el que nos informa que se a enviado el link de reset a nuestro correo</p><p><img src="'+t+'" alt="20250806005937.png"></p><p>Al revisar el correo, podemos observar que tenemos el link de reset con el token.</p><p><img src="'+l+'" alt="20250806005951.png"></p><p>Por otro lado, al revisar las solicitudes interceptadas por burpsuite tenemos una el que solo valida el nombre del usuario independiente del token, ya que este token es valido y se puede usar para el usuario Carlos y cambiarle la contraseña para posteriormente ingresar a su cuenta.</p><p><img src="'+d+'" alt="20250806010017.png"></p>',25)])])}const f=a(u,[["render",c]]);export{v as __pageData,f as default};
